# NL HHH.  Heerhugowaard - Hoorn
with detail = 2 {
    let hh = path("d2.nl.hhh");

    with railway = :first :cat:dc15 :pax {
        with link = "line.nl.HHH" {
            track(
                    hh[:her.yh, :her.xh] >> 0.5md << 0.5mt
                ..  hh[:her.zh, :her.zh + 7.01km]
            );
            line_label(:left:sw, hh[:her.zh + 7km] << 0.5mt, "HHH");
            track(
                    hh[:her.zh + 6.99km, :hoo.xh - 1md]
                ..  hh[:hoo.yh, :hoo.yh + 0.1dl] << 0.5md >> 0.5mt
            );
        }
    }
}

